137→function entryToRow(entry: NoteEntry): NoteRow {
138→  return {
139→    id: entry.id,
140→    title: entry.title,
141→    content: entry.content,
142→    created_at: entry.createdAt.toISOString(),
143→    updated_at: entry.updatedAt.toISOString(),
144→  };
145→}
