154→function NoteEditorView({ note, onSave }: NoteEditorViewProps) {
155→  const [title, setTitle] = useState(note?.title ?? '');
156→  const [content, setContent] = useState(note?.content ?? '');
157→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
158→  const titleRef = useRef(title);
159→  const contentRef = useRef(content);
160→  const onSaveRef = useRef(onSave);
161→
162→  titleRef.current = title;
163→  contentRef.current = content;
164→  onSaveRef.current = onSave;
165→
166→  const debounceSave = useCallback(() => {
167→    if (debounceRef.current) clearTimeout(debounceRef.current);
168→    debounceRef.current = setTimeout(() => {
169→      onSaveRef.current(titleRef.current, contentRef.current);
170→    }, 500);
171→  }, []);
172→
173→  useEffect(() => {
174→    return () => {
175→      if (debounceRef.current) {
176→        clearTimeout(debounceRef.current);
177→        onSaveRef.current(titleRef.current, contentRef.current);
178→      }
179→    };
180→  }, []);
181→
182→  const handleTitleChange = useCallback(
183→    (e: React.ChangeEvent<HTMLInputElement>) => {
184→      setTitle(e.target.value);
185→      debounceSave();
186→    },
187→    [debounceSave],
188→  );
189→
190→  const handleContentChange = useCallback(
191→    (e: React.ChangeEvent<HTMLTextAreaElement>) => {
192→      setContent(e.target.value);
193→      debounceSave();
194→    },
195→    [debounceSave],
196→  );
197→
198→  const handleSave = useCallback(() => {
199→    if (debounceRef.current) clearTimeout(debounceRef.current);
200→    onSaveRef.current(titleRef.current, contentRef.current);
201→  }, []);
202→
203→  useKeyboardShortcut(
204→    {
205→      key: 's',
206→      meta: true,
207→    },
208→    handleSave,
209→  );
210→
211→  return (
212→    <div className="notes-editor">
213→      <input
214→        className="notes-editor__title-input"
215→        type="text"
216→        value={title}
217→        onChange={handleTitleChange}
218→        placeholder="Note Title"
219→        aria-label="Note title"
220→        autoFocus
221→      />
222→      <textarea
223→        className="notes-editor__content-area"
224→        value={content}
225→        onChange={handleContentChange}
226→        placeholder="Start writing..."
227→        aria-label="Note content"
228→      />
229→      {note && (
230→        <div className="notes-editor__meta">
231→          <span>Modified {note.updatedAt.toLocaleString()}</span>
232→        </div>
233→      )}
234→    </div>
235→  );
236→}
